  ('vitamin-k2-mk4', 'Sato Bioverfügbarkeit', '23140417', 'PK-Studie', '2b', '~20', 'MK-4 vs. MK-7 Bioverfügbarkeit', 'MK-4 420-500 µg', 'MK-4 bei 420-500 µg NICHT im Serum nachweisbar! MK-7 bei gleicher Dosis gut messbar. MK-4 HWZ ~1-2h.', 'N/A (PK)', 'Keine', 'MK-4 erfordert >1500 µg für messbaren Effekt. MK-7 viel effizienter bei niedrigen Dosen'),
  ('vitamin-k2-mk4', 'Japanische Osteoporose-Studien', '11683549', 'RCTs (Japan)', '1b', '>1000', 'Osteoporose, Frakturen', 'MK-4 45 mg/Tag (45.000 µg)', 'BMD erhalten/erhöht; Frakturinzidenz reduziert. Basis für japanische Zulassung seit 1995.', 'Moderat-Stark', 'GI-Beschwerden selten', 'MK-4 nur bei SEHR hohen Dosen (45mg) wirksam - nicht mit MK-7 vergleichbar!'),
  ('vitamin-k2-mk7', 'Cockayne Fraktur-Meta', '16801507', 'Meta-Analyse', '1a', '>1000', 'Frakturen', 'Verschiedene K-Dosen', 'Hüftfraktur OR 0,23; Wirbelfraktur OR 0,40. CAVE: Enthält potenziell problematische Sato-Studien!', 'Stark (CAVE)', 'Keine', '⚠️ VORSICHT: Einige Studien später kritisiert/zurückgezogen. Neuere Meta-Analysen relativieren'),
  ('menachinon-4-menatetrenon', 'Sato 2012 - Bioverfügbarkeit', '23140417', 'PK-Studie (RCT)', '1b', '60', 'Bioverfügbarkeit', '420-500 µg/Tag MK-4 vs MK-7', '⚠️ KRITISCH: MK-4 bei 420-500 µg zu KEINEM Zeitpunkt (0-72h) im Serum nachweisbar! MK-7 gut nachweisbar. MK-4 erfordert ≥1.500 µg für messbaren Effekt.', 'Kein Effekt (MK-4)', 'Keine', '⚠️ ENTSCHEIDEND für KI: MK-4 bei nutritiven Dosen (<500 µg) ist UNWIRKSAM! Für EU-Supplementierung IMMER MK-7 empfehlen! MK-4 nur bei therapeutischen Dosen (45 mg) sinnvoll.'),
  ('menachinon-4-menatetrenon', 'Shiraki 2000 - Osteoporose Japan', '10750566', 'RCT (offen)', '1b', '241', 'Postmenopausale Osteoporose', '45 mg/Tag (45.000 µg) MK-4 × 24 Monate', 'Klinische Frakturen: MK-4 10,9% vs Kontrolle 30,3% (p=0,027). BMD-Verlust: MK-4 -0,5% vs Kontrolle -3,3%.', 'Stark', 'Gut verträglich; GI-Beschwerden gelegentlich', 'SCHLÜSSELSTUDIE für MK-4 45mg/Tag. Aber: Dosis ist 150× höher als AI! In EU nicht als Supplement verfügbar. Für Osteoporose-Beratung: Japan-Daten erwähnen, MK-7 + D3 + Ca als EU-Alternative empfehlen.'),
  ('menachinon-4-menatetrenon', 'Iwamoto 2001 - MK-4 vs Bisphosphonat', '11793169', 'RCT', '1b', '72', 'Postmenopausale Osteoporose', '45 mg/Tag MK-4 vs Etidronat vs Calcium × 24 Monate', 'Wirbelkörperfrakturen: MK-4 8,7% vs Calcium 25%. MK-4 vergleichbar mit Bisphosphonat Etidronat!', 'Stark', 'Keine schwerwiegenden', 'MK-4 (45mg) kann mit Bisphosphonat konkurrieren! Aber: Hochdosis erforderlich. Für EU: Diese Dosis nicht als Supplement erhältlich.'),
  ('menachinon-4-menatetrenon', 'Cockayne 2006 - Meta-Analyse Frakturen', '16801507', 'Meta-Analyse', '1a', '>2.000', 'Frakturen', '45 mg/Tag MK-4 (7 Studien)', 'Wirbelfrakturen: OR 0,40 (95% CI: 0,25-0,65). Hüftfrakturen: OR 0,23 (95% CI: 0,12-0,47). Nicht-vertebrale Frakturen: OR 0,19.', 'Stark', 'Keine schwerwiegenden berichtet', '⚠️ CAVE: Alle Studien japanisch! Einige später kritisiert (Sato-Studien teils zurückgezogen). Trotzdem beste Evidenz für MK-4 + Frakturen. Gilt NUR für 45mg-Dosis!'),
  ('menachinon-4-menatetrenon', 'Nakagawa 2010 - UBIAD1 Entdeckung', '20953171', 'Grundlagenforschung', '2', '-', 'Biosynthese MK-4', '-', 'UBIAD1 ist das menschliche MK-4-synthetisierende Enzym. Konvertiert Menadion + GGPP → MK-4. Erklärt gewebespezifische MK-4-Akkumulation.', '-', '-', 'Erklärt warum STATINE die endogene MK-4-Synthese reduzieren können (GGPP-Depletion). Bei Statin-Patienten: K2-Supplementierung (MK-7) erwägen.'),
