  ('mangangluconat', 'Mangangluconat', 'Eisenmangelanämie', 'Iron Deficiency Anemia', 'Relativ', '⚠️ KRITISCH: Bei Eisenmangel kompensatorische DMT1-Hochregulation → bis 5-FACH ERHÖHTE Mangan-Absorption! Erheblich gesteigertes Neurotoxizitätsrisiko!', 'Stark erhöhte Mn-Akkumulation im ZNS; Manganismus-Risiko deutlich erhöht', 'Freeland-Graves 1994, LPI', NULL, NULL, NULL, NULL),
