  ('marines-kollagen', 'Marines Kollagen', '❌ Fischallergie', 'Fish Allergy', 'ABSOLUT', '❌ Fisch ist EU-deklarierungspflichtiges Allergen (VO 1169/2011). Marines Kollagen stammt aus Fischhaut/-schuppen/-gräten.', 'Allergische Reaktion: Hautausschlag, Übelkeit, Atemprobleme bis ANAPHYLAXIE möglich! Erhitzung reduziert Allergenität NICHT vollständig.', 'EU VO 1169/2011; Allergologie', NULL, NULL, NULL, NULL),
  ('marines-kollagen', 'Marines Kollagen', 'Histaminintoleranz', 'Histamine Intolerance', 'Relativ', '⚠️ Fisch kann histaminreich sein, besonders bei minderwertiger Verarbeitung. Marines Kollagen kann Histamin enthalten.', 'Kopfschmerzen, Flush, GI-Beschwerden bei Histaminintoleranz', 'Allergologie', NULL, NULL, NULL, NULL),
  ('marines-kollagen', 'Marines Kollagen', 'Schwangerschaft (Schwermetalle)', 'Pregnancy (Heavy Metals)', 'Relativ', '⚠️ Marines Kollagen kann Schwermetalle enthalten (Arsen, Blei, Cadmium). Cammilleri 2025: 64% mit Arsen, 37% mit Blei.', 'Schwermetalle können fötale Entwicklung beeinträchtigen', 'Cammilleri 2025; Clean Label Project', NULL, NULL, NULL, NULL),
  ('marines-kollagen', 'Marines Kollagen', 'Nierensteine (Hydroxyprolin→Oxalat)', 'Kidney Stones (Hydroxyproline→Oxalate)', 'Relativ', '⚠️ Hydroxyprolin wird zu Oxalat metabolisiert. Bei hohen Dosen und Prädisposition für Oxalatsteine: Vorsicht.', 'Erhöhtes Nierensteinrisiko bei prädisponierten Personen', 'Stoffwechsel', NULL, NULL, NULL, NULL),
  ('bovines-kollagen', 'Bovines Kollagen', '❌ Alpha-Gal-Syndrom (AGS)', 'Alpha-Gal Syndrome (AGS)', 'ABSOLUT', '❌ AGS ist eine Allergie gegen Alpha-Gal (Galactose-α-1,3-Galactose), ausgelöst durch Zeckenbisse. Betrifft ALLE Säugetierprodukte inkl. bovines Kollagen und Gelatine!', 'Verzögerte Reaktion (3-6h nach Verzehr): Nesselsucht, GI-Beschwerden, Angioödem bis schwere ANAPHYLAXIE. ~450.000 Betroffene in USA.', 'CDC; Yale Medicine', NULL, NULL, NULL, NULL),
  ('bovines-kollagen', 'Bovines Kollagen', 'Rinderallergie', 'Beef Allergy', 'Absolut', '❌ Seltene, aber dokumentierte Allergie gegen Rinderproteine.', 'Allergische Reaktion', 'Allergologie', NULL, NULL, NULL, NULL),
  ('bovines-kollagen', 'Bovines Kollagen', 'Religiöse Einschränkungen (Halal/Koscher)', 'Religious Restrictions (Halal/Kosher)', 'Relativ', '⚠️ Bovines Kollagen ist nur halal wenn aus halal geschlachteten Rindern. Nur koscher wenn aus koscher geschlachteten Rindern.', 'Keine gesundheitliche Kontraindikation - religiöse/kulturelle Einschränkung', 'Halal/Koscher-Zertifizierung', NULL, NULL, NULL, NULL),
  ('bovines-kollagen', 'Bovines Kollagen', 'Religiöse Einschränkungen (Hindu)', 'Religious Restrictions (Hindu)', 'Relativ', '⚠️ Rinder werden im Hinduismus verehrt. Bovines Kollagen ist für viele Hindus nicht akzeptabel.', 'Keine gesundheitliche Kontraindikation - religiöse/kulturelle Einschränkung', 'Kulturell', NULL, NULL, NULL, NULL),
  ('bovines-kollagen', 'Bovines Kollagen', 'BSE/TSE-Bedenken (historisch)', 'BSE/TSE Concerns (historical)', 'Vernachlässigbar', '✅ EFSA 2024: BSE-Risiko durch bovines Kollagen ist 99-100% vernachlässigbar sicher. EU-Regelungen (VO 999/2001) gewährleisten Sicherheit.', 'Bei Einhaltung der EU-Vorschriften: Kein relevantes Risiko', 'EFSA 2024; EU VO 999/2001', NULL, NULL, NULL, NULL),
  ('l-threonin', 'L-Threonin', 'ALS (Amyotrophe Lateralsklerose)', 'ALS (Amyotrophic Lateral Sclerosis)', 'Absolut', 'Kontrollierte Studie zeigte höhere Rate an Lungenfunktionsverlust bei ALS-Patienten unter L-Threonin/BCAAs.', '⚠️ Beschleunigte Verschlechterung der Atemfunktion möglich.', 'Kontrollierte ALS-Studie; RxList', NULL, NULL, NULL, NULL),
  ('l-threonin', 'L-Threonin', 'Memantin-Therapie', 'Memantine Therapy', 'Relativ', 'Theoretische Wechselwirkung: Threonin kann NMDA-Rezeptor modulieren; Memantin ist NMDA-Antagonist.', 'Klinische Relevanz unklar; Vorsicht empfohlen.', 'RxList; theoretisch', NULL, NULL, NULL, NULL),
  ('l-tryptophan', 'L-Tryptophan', 'MAO-Hemmer-Therapie', 'MAOI Therapy', 'Absolut', '⚠️⚠️⚠️ MAO-A baut Serotonin ab. MAO-Hemmung + Tryptophan → massive Serotonin-Akkumulation.', '❌❌❌ LEBENSBEDROHLICHES SEROTONIN-SYNDROM! Erste dokumentierte Fälle in 1960ern. Hyperthermie >41°C, Klonus, Rigidität, Tod möglich.', 'StatPearls; Hunter Criteria; FDA', NULL, NULL, NULL, NULL),
  ('l-tryptophan', 'L-Tryptophan', 'SSRI-Therapie', 'SSRI Therapy', 'Absolut', 'SSRIs erhöhen synaptisches Serotonin; Tryptophan erhöht Serotonin-Synthese → additive/synergistische Wirkung.', '⚠️⚠️ SEROTONIN-SYNDROM-RISIKO! Washout nach SSRIs: 2 Wochen; nach Fluoxetin: 5 Wochen!', 'StatPearls; FDA; Medscape', NULL, NULL, NULL, NULL),
  ('l-tryptophan', 'L-Tryptophan', 'SNRI-Therapie', 'SNRI Therapy', 'Absolut', 'SNRIs (Venlafaxin, Duloxetin) hemmen auch Serotonin-Wiederaufnahme.', '⚠️⚠️ SEROTONIN-SYNDROM-RISIKO wie bei SSRIs!', 'StatPearls; FDA', NULL, NULL, NULL, NULL),
  ('l-tryptophan', 'L-Tryptophan', 'Tramadol-Therapie', 'Tramadol Therapy', 'Absolut', 'Tramadol hemmt Serotonin-Wiederaufnahme zusätzlich zu Opioid-Wirkung.', '⚠️⚠️ SEROTONIN-SYNDROM-RISIKO besonders bei Polypharmazie!', 'FDA; StatPearls', NULL, NULL, NULL, NULL),
