  ('l-tryptophan', 'L-Tryptophan', 'Bekannte EMS-Anamnese', 'Known EMS History', 'Absolut', 'Patienten mit EMS-Vorgeschichte haben erhöhte Sensitivität.', 'Re-Exposition vermeiden auch bei heutigen hochreinen Produkten.', 'CDC; COT UK', NULL, NULL, NULL, NULL),
