  ('l-tryptophan', 'L-Tryptophan', 'Karzinoid-Syndrom', 'Carcinoid Syndrome', 'Relativ', 'Karzinoid-Tumoren produzieren exzessiv Serotonin aus Tryptophan.', 'Tryptophan-Supplementierung kann Serotonin-Überproduktion verstärken.', 'Onkologie-Literatur', NULL, NULL, NULL, NULL),
  ('huehner-kollagen', 'Hühner-Kollagen', 'Hühnerallergie / Geflügelallergie', 'Chicken Allergy / Poultry Allergy', 'Absolut', '❌ Hühnerallergie ist selten (0-13% unter Allergikern), aber bei Vorliegen ist Hühner-Kollagen kontraindiziert.', 'Allergische Reaktion: Hautausschlag, Übelkeit, Atemprobleme bis Anaphylaxie möglich', 'Thermo Fisher Allergen Encyclopedia f83', NULL, NULL, NULL, NULL),
  ('huehner-kollagen', 'Hühner-Kollagen', 'Vogel-Ei-Syndrom (Bird-Egg-Syndrome)', 'Bird-Egg Syndrome', 'Relativ', '⚠️ Kreuzreaktivität zwischen Vogel-Serumalbumin (Gal d 5) und Ei. Bei 22-37% der dualen Ei-Vogel-Allergiker. ABER: Kreuzreaktivität mit verarbeitetem Kollagen ist SELTEN (5-6%).', 'Allergische Reaktion möglich, aber selten bei verarbeitetem Kollagen', 'PMC4861744; Thermo Fisher', NULL, NULL, NULL, NULL),
  ('huehner-kollagen', 'Hühner-Kollagen', '✅ Alpha-Gal-Syndrom (AGS) - SICHER!', 'Alpha-Gal Syndrome - SAFE!', 'KEINE Kontraindikation!', '✅ Geflügel enthält KEIN Alpha-Gal! Hühner-Kollagen ist SICHER für AGS-Patienten! Dies ist ein VORTEIL gegenüber Rind/Schwein!', 'Keine Reaktion - Huhn ist SICHER bei AGS!', 'CDC; Wikipedia Alpha-gal', NULL, NULL, NULL, NULL),
  ('schweine-kollagen', 'Schweine-Kollagen (Porcin)', '❌ Halal-Einschränkung (HARAM)', 'Halal Restriction (HARAM)', 'ABSOLUT', '❌ Schwein ist für Muslime STRIKT VERBOTEN (HARAM) - unabhängig von Verarbeitungsgrad! Keine Ausnahme für Kollagen oder Gelatine! ~46-50 Millionen Muslime in der EU (~6%).', 'Keine gesundheitliche Reaktion - religiöse/kulturelle Kontraindikation', 'Islamisches Recht; Pew Research', NULL, NULL, NULL, NULL),
  ('schweine-kollagen', 'Schweine-Kollagen (Porcin)', '❌ Koscher-Einschränkung (TREIF)', 'Kosher Restriction (TREIF)', 'ABSOLUT', '❌ Schwein ist für Juden STRIKT VERBOTEN (TREIF) gemäß Levitikus 11:7. Keine Ausnahme für Kollagen oder Gelatine!', 'Keine gesundheitliche Reaktion - religiöse/kulturelle Kontraindikation', 'Jüdisches Recht (Kashrut)', NULL, NULL, NULL, NULL),
  ('schweine-kollagen', 'Schweine-Kollagen (Porcin)', '❌ Alpha-Gal-Syndrom (AGS)', 'Alpha-Gal Syndrome (AGS)', 'ABSOLUT', '❌ AGS ist Allergie gegen Alpha-Gal, das in ALLEN Säugetieren vorkommt - einschließlich Schwein! ~450.000 Betroffene in USA; bis 30% Sensibilisierung bei Forstarbeitern in DE. Reaktion 3-6h verzögert!', 'Verzögerte Reaktion (3-6h): Nesselsucht, GI-Beschwerden, Angioödem bis schwere ANAPHYLAXIE', 'CDC; Alpha-gal Information', NULL, NULL, NULL, NULL),
  ('schweine-kollagen', 'Schweine-Kollagen (Porcin)', 'Katz-Schwein-Syndrom', 'Cat-Pork Syndrome', 'Relativ', '⚠️ Kreuzreaktion zwischen Katzen-Serumalbumin (Fel d 2) und Schweine-Serumalbumin. ~14-23% der Katzenallergiker sind auf Fel d 2 sensibilisiert. ABER: Serumalbumin ist NICHT in reinem Kollagen enthalten - Reinheit prüfen!', 'Allergische Reaktion bei Katzenallergikern möglich, aber nur bei unreinen Produkten', 'Allergologie; PMC', NULL, NULL, NULL, NULL),
  ('schweine-kollagen', 'Schweine-Kollagen (Porcin)', 'Schweineallergie (primär)', 'Pork Allergy (primary)', 'Absolut', '❌ Primäre Schweinefleischallergie ist SELTEN, aber dokumentiert.', 'Allergische Reaktion', 'Allergologie', NULL, NULL, NULL, NULL),
  ('schweine-kollagen', 'Schweine-Kollagen (Porcin)', '✅ BSE/TSE-Risiko - KEINES!', 'BSE/TSE Risk - NONE!', 'KEINE Kontraindikation!', '✅ Schweine sind NICHT natürlich TSE-anfällig! NIEMALS natürliche Prionenkrankheit bei Schweinen berichtet. KEIN BSE-Risiko bei porcinem Kollagen! Dies ist ein VORTEIL gegenüber bovinem Kollagen.', 'Kein Risiko', 'EMA; EU VO 999/2001', NULL, NULL, NULL, NULL),
  ('l-valin', 'L-Valin', 'MSUD (Ahornsirupkrankheit)', 'MSUD (Maple Syrup Urine Disease)', 'Absolut', '⚠️⚠️⚠️ BCKDH-Enzymkomplex-Defekt. Valin (und alle BCAAs) können nicht abgebaut werden → toxische Akkumulation.', '❌❌❌ LEBENSBEDROHLICH! Unbehandelt: Tod innerhalb 2 Monaten. Symptome: Ahornsirupgeruch (Sotolone), Enzephalopathie, Hirnödem, Koma.', 'GeneReviews NBK1319; MedlinePlus; StatPearls', NULL, NULL, NULL, NULL),
  ('l-valin', 'L-Valin (+ alle BCAAs)', 'ALS (Amyotrophe Lateralsklerose)', 'ALS (Amyotrophic Lateral Sclerosis)', 'Absolut', '⚠️⚠️ Klinische Studie (n=126) wegen erhöhter Mortalität ABGEBROCHEN. 24 vs. 13 Todesfälle unter BCAAs.', '❌❌ FVC (Lungenfunktion) sank 2,5x SCHNELLER unter BCAA-Therapie. "Taking BCAAs is not beneficial in ALS. It might make lung function worse and increase chance of death."', 'PubMed 8255440; Neurology 1996; WebMD', NULL, NULL, NULL, NULL),
  ('l-leucin', 'L-Leucin (+ alle BCAAs)', 'ALS (Amyotrophe Lateralsklerose)', 'ALS (Amyotrophic Lateral Sclerosis)', 'Absolut', '⚠️⚠️ Hochdosierte BCAAs (Leu 12g + Ile 6g + Val 6g/Tag) führten zu signifikant erhöhter Mortalität.', '❌❌ Studie vorzeitig beendet. Mechanismus unklar, aber Effekt eindeutig negativ.', 'PubMed 8255440', NULL, NULL, NULL, NULL),
  ('l-valin', 'L-Valin', 'Eingeschränkte Nierenfunktion', 'Impaired Kidney Function', 'Relativ', 'Aminosäuren werden renal ausgeschieden. Bei Niereninsuffizienz kann Akkumulation auftreten.', 'Erhöhte Harnstoff-/Ammoniak-Spiegel möglich. Protein- und Aminosäureaufnahme oft limitiert.', 'BfR 2019; Nephrologische Leitlinien', NULL, NULL, NULL, NULL),
  ('l-leucin', 'L-Leucin', 'Eingeschränkte Nierenfunktion', 'Impaired Kidney Function', 'Relativ', 'Leucin-Abbauprodukte belasten Nieren. Bei CKD ist Proteinrestriktion oft indiziert.', 'Ärztliche Rücksprache vor BCAA-Supplementierung bei Nierenpatienten.', 'BfR 2019', NULL, NULL, NULL, NULL),
  ('l-valin', 'L-Valin', 'Schwangerschaft', 'Pregnancy', 'Relativ', '⚠️ BfR 2019: "Schwangere sollten isolierte BCAAs MEIDEN". Unzureichende Sicherheitsdaten.', 'Keine kontrollierten Studien in Schwangerschaft. Nahrungsprotein ist sicherer.', 'BfR Opinion 052/2019', NULL, NULL, NULL, NULL),
  ('l-leucin', 'L-Leucin', 'Schwangerschaft', 'Pregnancy', 'Relativ', '⚠️ BfR: Schwangere sollen isolierte BCAAs meiden. Leucin als mTOR-Aktivator theoretisch bedenklich.', 'Protein aus Nahrung bevorzugen; keine isolierten BCAA-Supplemente.', 'BfR 2019', NULL, NULL, NULL, NULL),
