  ('clear-whey-isolat', 'Clear Whey Isolat', 'Kuhmilchallergie (CMA)', 'Cow Milk Allergy', 'Absolut', '❌❌ LEBENSBEDROHLICH! "Clear" bezieht sich NUR auf Konsistenz - enthält weiterhin allergene Molkenproteine (β-Lactoglobulin, α-Lactalbumin). ~80% der Milchallergiker reagieren auf β-Lactoglobulin.', '❌❌ ANAPHYLAXIE möglich! Symptome: Urtikaria, Angioödem, Bronchospasmus, Blutdruckabfall, TOD.', 'Mayo Clinic; Cleveland Clinic; PMC9778632', NULL, NULL, NULL, NULL),
  ('clear-whey-isolat', 'Clear Whey Isolat', 'Chronische Nierenerkrankung (CKD)', 'Chronic Kidney Disease', 'Relativ', '⚠️ Bei CKD wird Proteinrestriktion empfohlen (0,6-0,8g/kg/Tag).', '⚠️ Mögliche Verschlechterung der Nierenfunktion bei vorbestehender CKD.', 'KDIGO-Leitlinien', NULL, NULL, NULL, NULL),
  ('casein-protein', 'Casein Protein', 'Kuhmilchallergie (CMA)', 'Cow Milk Allergy', 'Absolut', '❌❌❌ CASEIN IST DAS HAUPTALLERGEN IN KUHMILCH! 100% IgE-Reaktivität bei Milchallergikern (PMID 8837665). αS1-Casein ist das dominante Allergen. WHO-Klassifizierung: Bos d 8.', '❌❌❌ ANAPHYLAXIE möglich! Casein ist gefährlicher als Molkenproteine! 15% der allergischen Kinder bleiben lebenslang allergisch.', 'PMID 8837665; PMID 8836334; NCBI Bookshelf NBK542243', NULL, NULL, NULL, NULL),
  ('casein-protein', 'Casein Protein', 'Chronische Nierenerkrankung (CKD)', 'Chronic Kidney Disease', 'Relativ', '⚠️ Bei CKD wird Proteinrestriktion empfohlen. Pre-Sleep-Supplementierung mit hohen Dosen (30-40g) problematisch.', '⚠️ Mögliche Verschlechterung der Nierenfunktion.', 'KDIGO-Leitlinien', NULL, NULL, NULL, NULL),
  ('casein-protein', 'Casein Protein', 'Phenylketonurie (PKU)', 'Phenylketonuria', 'Relativ', '⚠️ Casein enthält Phenylalanin (~5% des Proteins - höher als Whey).', '⚠️ Neurotoxizität durch Phenylalanin-Akkumulation bei PKU.', 'Stoffwechselmedizin', NULL, NULL, NULL, NULL),
  ('clear-whey-isolat', 'Clear Whey Isolat', 'Phenylketonurie (PKU)', 'Phenylketonuria', 'Relativ', '⚠️ Enthält Phenylalanin (~3-4% des Proteins).', '⚠️ Neurotoxizität durch Phenylalanin-Akkumulation bei PKU.', 'Stoffwechselmedizin', NULL, NULL, NULL, NULL),
  ('casein-protein', 'Casein Protein', 'Laktoseintoleranz (je nach Form)', 'Lactose Intolerance', 'Relativ (formabhängig)', '⚠️ FORMABHÄNGIG: Micellar Casein kann Laktose enthalten; Caseinate haben sehr niedrigen Laktosegehalt.', '⚠️ GI-Beschwerden bei Micellar Casein mit höherem Laktosegehalt möglich.', 'Produktspezifikationen', NULL, NULL, NULL, NULL),
  ('clear-whey-isolat', 'Clear Whey Isolat', 'Fehlannahme: Clear = Allergenfrei', 'Misconception: Clear = Allergen-Free', 'Absolut (bei CMA)', '❌❌ KRITISCHES MISSVERSTÄNDNIS! "Clear" beschreibt NUR die optische Erscheinung (transparent, saftähnlich). Das Produkt enthält weiterhin 100% der allergenen Molkenproteine.', '❌❌ Allergische Reaktionen bis Anaphylaxie möglich! Alle Hersteller deklarieren "CONTAINS: MILK".', 'Alle Herstellerangaben; EU-VO 1169/2011', NULL, NULL, NULL, NULL),
