  ('lactiplantibacillus-plantarum', 'Lactiplantibacillus plantarum', '⚠️ SCHWERE AKUTE PANKREATITIS', 'Severe Acute Pancreatitis', 'Absolut', '⚠️ PROPATRIA-Studie: Probiotika-Mischung erhöhte Mortalität (16% vs. 6%, p=0,01)! Mechanismus: Darm-Ischämie.', '⚠️ TOD! Darm-Ischämie, Multi-Organ-Versagen', 'Besselink et al. Lancet 2008 (PMID: 18215705)', NULL, NULL, NULL, NULL),
  ('lactiplantibacillus-plantarum', 'Lactiplantibacillus plantarum', 'Schwere Immunsuppression', 'Severe Immunosuppression', 'Relativ', '⚠️ Theoretisches Risiko für bakterielle Translokation bei stark immunsupprimierten Patienten.', 'Bakteriämie, Sepsis (theoretisch)', 'Allgemeine Probiotika-Sicherheitsdaten', NULL, NULL, NULL, NULL),
  ('lactiplantibacillus-plantarum', 'Lactiplantibacillus plantarum', 'Zentralvenöse Katheter (ZVK)', 'Central Venous Catheters', 'Relativ', 'Erhöhtes Risiko für Katheter-assoziierte Infektionen bei kritisch Kranken mit ZVK.', 'Katheter-assoziierte Infektion', 'ICU-Sicherheitsdaten', NULL, NULL, NULL, NULL),
  ('levilactobacillus-brevis', 'Levilactobacillus brevis', '⚠️ MAO-INHIBITOR-THERAPIE', 'MAO Inhibitor Therapy', 'Absolut', '⚠️ KRITISCH! L. brevis produziert TYRAMIN. Bei MAO-Inhibitoren blockiert MAO den Tyramin-Abbau → HYPERTENSIVE KRISE!', '⚠️ HYPERTENSIVE KRISE! Kopfschmerzen, Blutdruckspitzen, kardiovaskuläre Ereignisse, potenziell lebensbedrohlich.', 'MAO-Inhibitor-Interaktionslisten; Biogene Amine-Literatur', NULL, NULL, NULL, NULL),
  ('levilactobacillus-brevis', 'Levilactobacillus brevis', 'Histaminintoleranz (stammabhängig)', 'Histamine Intolerance', 'Relativ', 'L. brevis ist KEIN primärer Histamin-Produzent, produziert aber Tyramin und Putrescin. Stammabhängige Prüfung erforderlich.', 'GI-Beschwerden, Kopfschmerzen, Flush (bei empfindlichen Patienten)', 'Biogene Amine Review', NULL, NULL, NULL, NULL),
  ('levilactobacillus-brevis', 'Levilactobacillus brevis', 'Schwere Immunsuppression', 'Severe Immunosuppression', 'Relativ', 'Wie bei anderen Probiotika: theoretisches Translokationsrisiko bei schwerer Immunsuppression.', 'Bakteriämie (theoretisch)', 'Allgemeine Probiotika-Sicherheitsdaten', NULL, NULL, NULL, NULL),
  ('levilactobacillus-brevis', 'Levilactobacillus brevis', 'Schwere akute Pankreatitis', 'Severe Acute Pancreatitis', 'Absolut', 'PROPATRIA-Ergebnisse gelten für alle Probiotika.', '⚠️ TOD!', 'PROPATRIA', NULL, NULL, NULL, NULL),
  ('calciumbutyrat', 'Calciumbutyrat', '❌ Hyperkalzämie', 'Hypercalcemia', 'Absolut', '❌ Bei erhöhtem Calcium-Spiegel (>2,6 mmol/L) kontraindiziert. Calciumbutyrat liefert ~186 mg Ca/g.', 'Weitere Ca-Erhöhung, Nierensteine, Herzrhythmusstörungen.', '❌ Bei Hyperkalzämie: Natriumbutyrat oder Tributyrin verwenden!', NULL, NULL, NULL, NULL),
  ('calciumbutyrat', 'Calciumbutyrat', '⚠️ Schwere Niereninsuffizienz (Ca-Akkumulation)', 'Severe Renal Insufficiency', 'Relativ', '⚠️ Bei GFR <30: Calcium-Akkumulation möglich da eingeschränkte renale Ausscheidung.', 'Hyperkalzämie, Weichteilverkalkung.', '⚠️ Bei CKD Stadium 4-5: Ca-Spiegel engmaschig überwachen oder Tributyrin verwenden.', NULL, NULL, NULL, NULL),
  ('calciumbutyrat', 'Calciumbutyrat', '⚠️ Hyperparathyreoidismus', 'Hyperparathyroidism', 'Relativ', '⚠️ Bei primärem Hyperparathyreoidismus bereits erhöhte Ca-Mobilisation aus Knochen.', 'Verstärkte Hyperkalzämie.', '⚠️ Bei Hyperparathyreoidismus: Vorsicht mit Ca-haltigen Supplementen.', NULL, NULL, NULL, NULL),
  ('magnesiumbutyrat', 'Magnesiumbutyrat', '❌ Schwere Niereninsuffizienz (Mg-Akkumulation)', 'Severe Renal Insufficiency', 'Absolut bei GFR<30', '❌ Bei GFR <30: Magnesium-Akkumulation da eingeschränkte renale Ausscheidung. Magnesiumbutyrat liefert ~122 mg Mg/g.', 'Hypermagnesiämie: Muskelschwäche, Hypotonie, Atemlähmung.', '❌ Bei CKD Stadium 4-5: Magnesiumbutyrat KONTRAINDIZIERT! Calciumbutyrat oder Tributyrin verwenden.', NULL, NULL, NULL, NULL),
  ('magnesiumbutyrat', 'Magnesiumbutyrat', '⚠️ Myasthenia gravis', 'Myasthenia Gravis', 'Relativ', '⚠️ Magnesium kann neuromuskuläre Übertragung beeinträchtigen.', 'Verstärkte Muskelschwäche.', '⚠️ Bei Myasthenia gravis: Mg-haltige Supplemente mit Vorsicht.', NULL, NULL, NULL, NULL),
  ('magnesiumbutyrat', 'Magnesiumbutyrat', '⚠️ AV-Block II-III°', 'AV Block II-III', 'Relativ', '⚠️ Magnesium kann AV-Überleitung verzögern.', 'Verstärkte Bradykardie.', '⚠️ Bei höhergradigem AV-Block: Mg-Supplemente mit Vorsicht.', NULL, NULL, NULL, NULL),
  ('calcium-magnesium-butyrat', 'Ca-Mg-Butyrat', '⚠️ Kombinierte Ca/Mg-Kontraindikationen', 'Combined Ca/Mg Contraindications', 'Relativ', '⚠️ Kombination enthält BEIDE Mineralien - alle Kontraindikationen von Ca UND Mg beachten!', 'Siehe einzelne Mineralien.', '⚠️ Bei Niereninsuffizienz besonders problematisch (Ca + Mg Akkumulation)! Tributyrin bevorzugen.', NULL, NULL, NULL, NULL),
  ('butyrat-alle', 'Alle Butyrat-Formen', '⚠️ Unkontrollierte Hypertonie', 'Uncontrolled Hypertension', 'Relativ', '⚠️ RCT-Studie zeigt Blutdruckerhöhung durch orales Butyrat möglich (+10 mmHg systolisch)! Widerspricht Tierstudien.', 'Blutdruckerhöhung, kardiovaskuläres Risiko.', '⚠️ Bei Hypertonie: Engmaschige RR-Kontrolle! Falls RR steigt → Butyrat absetzen.', NULL, NULL, NULL, NULL),
  ('resistente-staerke-typ2', 'Resistente Stärke Typ 2', '⚠️ Akute Gastroenteritis', 'Acute Gastroenteritis', 'Relativ', 'Fermentation kann GI-Symptome während akuter Erkrankung verschlimmern.', 'Verstärkte Blähungen, Krämpfe, Durchfall', 'Allgemein', NULL, NULL, NULL, NULL),
  ('resistentes-maltodextrin', 'Resistentes Maltodextrin', '⚠️ Akute Gastroenteritis', 'Acute Gastroenteritis', 'Relativ', 'Auch RMD kann bei akuter GI-Erkrankung belastend sein, trotz guter Verträglichkeit.', 'Mögliche Symptomverschlechterung', 'Allgemein', NULL, NULL, NULL, NULL),
  ('resistente-staerke-typ2', 'Resistente Stärke Typ 2', '❌ Intestinale Obstruktion', 'Intestinal Obstruction', 'Absolut', 'Unlösliche Ballaststoffe können Obstruktion verschlimmern.', 'Verschlimmerung der Obstruktion', 'Allgemein', NULL, NULL, NULL, NULL),
  ('resistente-staerke-typ2', 'Resistente Stärke Typ 2', '⚠️ Schweres IBS-D', 'Severe IBS-D', 'Relativ', '⚠️ Bei schwerem IBS-D RS2 mit Vorsicht! RS4 (Fibersym) oder RMD (Nutriose) bevorzugen - beide LOW-FODMAP.', 'GI-Beschwerden möglich bei empfindlichen Personen', 'Monash University', NULL, NULL, NULL, NULL),
  ('resistentes-maltodextrin', 'Resistentes Maltodextrin', '✅ Keine absoluten Kontraindikationen', 'No absolute contraindications', '-', '✅ RMD hat die BESTE Verträglichkeit aller Ballaststoffe (65g/d). Keine bekannten absoluten Kontraindikationen.', '-', 'PMID 24064737', NULL, NULL, NULL, NULL),
  ('pektin', 'Pektin', '❌ Schluckstörungen / Dysphagie', 'Dysphagia', 'Absolut', '❌ ERSTICKUNGSGEFAHR! Pektin geliert und kann bei Schluckstörungen Atemwege blockieren.', 'Erstickung, Aspiration.', '❌ Bei Schluckstörungen: Pektin KONTRAINDIZIERT!', NULL, NULL, NULL, NULL),
  ('pektin', 'Pektin', '⚠️ Darmverschluss / Ileus', 'Intestinal Obstruction', 'Absolut', '❌ Ballaststoffe können bei bestehendem Ileus die Situation verschlimmern.', 'Verschlimmerung des Ileus.', '❌ Bei Ileus: Alle Ballaststoffe kontraindiziert!', NULL, NULL, NULL, NULL),
  ('pektin', 'Pektin', '⚠️ Gleichzeitige Medikamenteneinnahme', 'Drug Absorption', 'Relativ', '⚠️ Pektin kann Medikamenten-Absorption reduzieren durch Gelbildung.', 'Reduzierte Medikamentenwirkung.', '⚠️ Mindestens 30-60 Minuten Abstand zu Medikamenten!', NULL, NULL, NULL, NULL),
  ('hafer-beta-glucan', 'Hafer-Beta-Glucan', '⚠️ Glutenunverträglichkeit / Zöliakie', 'Celiac Disease', 'Relativ', '⚠️ Hafer kann Spuren von Gluten enthalten. Zertifiziert glutenfreie Produkte verwenden.', 'Zöliakie-Reaktion bei kontaminiertem Hafer.', '⚠️ Bei Zöliakie: Nur zertifiziert glutenfreien Hafer verwenden!', NULL, NULL, NULL, NULL),
  ('gerste-beta-glucan', 'Gerste-Beta-Glucan', '❌ Zöliakie / Glutenunverträglichkeit', 'Celiac Disease', 'Absolut', '❌ Gerste enthält GLUTEN! Bei Zöliakie absolut kontraindiziert.', 'Zöliakie-Reaktion, Darmschädigung.', '❌ Bei Zöliakie: Gerste KONTRAINDIZIERT! Hafer (glutenfrei) als Alternative.', NULL, NULL, NULL, NULL),
  ('pilz-beta-glucan', 'Pilz-Beta-Glucan', '⚠️ Immunsuppressive Therapie', 'Immunosuppression', 'Relativ', '⚠️ Pilz-Beta-Glucane sind IMMUNSTIMULIEREND (Dectin-1). Können Immunsuppression antagonisieren.', 'Reduzierte Wirkung der Immunsuppression, Abstoßungsrisiko.', '⚠️ Bei Organtransplantation/Autoimmunerkrankung: Ärztliche Absprache!', NULL, NULL, NULL, NULL),
  ('pilz-beta-glucan', 'Pilz-Beta-Glucan', '⚠️ Pilzallergie', 'Mushroom Allergy', 'Absolut', '❌ Bei bekannter Pilzallergie: Pilz-Beta-Glucane kontraindiziert.', 'Allergische Reaktion.', '❌ Bei Pilzallergie: Hefe-Beta-Glucan (Wellmune) als Alternative prüfen.', NULL, NULL, NULL, NULL),
  ('hefe-beta-glucan', 'Hefe-Beta-Glucan', '⚠️ Hefeallergie', 'Yeast Allergy', 'Absolut', '❌ Bei bekannter Hefeallergie: Hefe-Beta-Glucan kontraindiziert.', 'Allergische Reaktion.', '❌ Bei Hefeallergie: Pilz-Beta-Glucane als Alternative prüfen.', NULL, NULL, NULL, NULL),
  ('tributyrin', 'Tributyrin', '❌❌ EU Novel Food NICHT ZUGELASSEN', 'EU Novel Food NOT AUTHORIZED', 'Absolut (regulatorisch)', '⚠️⚠️ Synthetisches Tributyrin ist in der EU als Novel Food klassifiziert und NICHT zugelassen! RASFF 2024.8392.', 'Rechtliche Konsequenzen für Verkäufer. Produkte können beschlagnahmt werden.', 'EU Novel Food Catalogue; RASFF 2024.8392', NULL, NULL, NULL, NULL),
  ('tributyrin', 'Tributyrin', '⚠️ Schwangerschaft/Stillzeit', 'Pregnancy/Lactation', 'Relativ', 'KEINE Sicherheitsdaten für Schwangere/Stillende.', 'Unbekannte Risiken', 'Allgemein', NULL, NULL, NULL, NULL),
  ('propionat', 'Propionat (Natriumpropionat)', '❌ Propionazidurie', 'Propionic Acidemia', 'Absolut', 'Seltener angeborener Stoffwechseldefekt. Propionat-Abbau gestört.', 'Metabolische Krise möglich!', 'Genetische Erkrankung', NULL, NULL, NULL, NULL),
  ('propionat', 'Propionat (Natriumpropionat)', '⚠️ Vitamin-B12-Mangel', 'Vitamin B12 Deficiency', 'Relativ', 'Vitamin B12 ist Cofaktor für Propionat-Metabolismus (Methylmalonyl-CoA-Mutase).', 'Theoretisch gestörter Propionat-Abbau', 'Allgemein', NULL, NULL, NULL, NULL),
  ('propionat', 'Propionat (Natriumpropionat)', '⚠️ Schwere Immunsuppression', 'Severe Immunosuppression', 'Relativ', 'Propionat moduliert Immunsystem (Treg↑). Theoretische Interaktion mit Immunsuppressiva.', 'Unklare Wechselwirkung möglich', 'Allgemein', NULL, NULL, NULL, NULL),
  ('lactobacillus-delbrueckii-bulgaricus', 'Lactobacillus delbrueckii subsp. bulgaricus', '⚠️ HISTAMININTOLERANZ (stammspezifisch!)', 'Histamine Intolerance (strain-specific)', 'Relativ', '⚠️ EINIGE L. bulgaricus-Stämme produzieren HISTAMIN! Histidin-Decarboxylase (HDC) vorhanden. Beispiel: TISTR 895: 459 mg/L Histamin.', 'Histamin-Symptome: Kopfschmerzen, Flush, GI-Beschwerden, Hautreaktionen.', 'Histaminproduktion Literatur', NULL, NULL, NULL, NULL),
  ('lactobacillus-delbrueckii-bulgaricus', 'Lactobacillus delbrueckii subsp. bulgaricus', 'Schwere Immunsuppression', 'Severe Immunosuppression', 'Relativ', 'Theoretisches Translokationsrisiko bei schwerer Immunsuppression.', 'Bakteriämie (selten)', 'Allgemeine Probiotika-Sicherheitsdaten', NULL, NULL, NULL, NULL),
