  ('lactobacillus-delbrueckii-bulgaricus', 'Lactobacillus delbrueckii subsp. bulgaricus', 'Schwere akute Pankreatitis', 'Severe Acute Pancreatitis', 'Absolut', 'PROPATRIA-Studie gilt für alle Probiotika.', '⚠️ Erhöhte Mortalität!', 'PROPATRIA', NULL, NULL, NULL, NULL),
