  ('limosilactobacillus-fermentum', 'Limosilactobacillus fermentum', 'Kritisch Kranke (PROPATRIA)', 'Critically Ill (PROPATRIA)', 'Absolut', '⚠️ PROPATRIA-Studie: Erhöhte Mortalität bei schwerer akuter Pankreatitis mit Probiotika-Mischung.', '⚠️ Erhöhte Mortalität!', 'Besselink et al. Lancet 2008', NULL, NULL, NULL, NULL),
  ('limosilactobacillus-fermentum', 'Limosilactobacillus fermentum', '✅ KEINE Histamin-Kontraindikation (CECT5716)', 'NO Histamine Contraindication (CECT5716)', '-', '✅ CECT5716: KEINE Produktion von Tyramin, Histamin, Putrescin, Cadaverin nachgewiesen! Vorteilhaft für Histaminintolerante.', '-', 'CECT5716 Sicherheitsdaten', NULL, NULL, NULL, NULL),
  ('acetat', 'Acetat/Apfelessig', '⚠️ Hypokaliämie', 'Hypokalemia', 'Relativ', '⚠️ Langzeit-Acetat-Konsum kann Kalium senken (renale Ausscheidung ↑).', 'Muskelschwäche, Herzrhythmusstörungen.', '⚠️ Bei Langzeitanwendung: Kalium überwachen!', NULL, NULL, NULL, NULL),
