  ('apfelessig', 'Apfelessig', '⚠️ Gastroparese', 'Gastroparesis', 'Relativ', '⚠️ Essig verzögert Magenentleerung zusätzlich!', 'Verstärkte Symptome, Hypoglykämie bei Diabetes.', '⚠️ Bei Gastroparese: Nicht empfohlen.', NULL, NULL, NULL, NULL),
  ('natriumacetat', 'Natriumacetat', '⚠️ Hypertonie / Herzinsuffizienz', 'Hypertension', 'Relativ', '⚠️ Na-Belastung! 209 mg Na pro Gramm Natriumacetat.', 'Blutdruckerhöhung, Flüssigkeitsretention.', '⚠️ Bei Hypertonie: Calciumacetat bevorzugen!', NULL, NULL, NULL, NULL),
  ('calciumacetat', 'Calciumacetat', '❌ Hyperkalzämie', 'Hypercalcemia', 'Absolut', '❌ Bei bestehender Hyperkalzämie kontraindiziert!', 'Verstärkte Hyperkalzämie mit Symptomen.', '❌ Bei Hyperkalzämie: Calciumacetat kontraindiziert!', NULL, NULL, NULL, NULL),
  ('calciumacetat', 'Calciumacetat', '⚠️ Hyperparathyreoidismus', 'Hyperparathyroidism', 'Relativ', '⚠️ Bereits erhöhte Ca-Spiegel möglich.', 'Hyperkalzämie.', '⚠️ Ca-Spiegel vor Therapie prüfen!', NULL, NULL, NULL, NULL),
  ('kefiran', 'Kefiran (aus Kefir)', '⚠️ Milchallergie', 'Milk Allergy', 'Relativ', '⚠️ Kefir enthält Milchproteine. Bei Milchallergie: wasserkefir.', 'Allergische Reaktion.', '⚠️ Bei Milchallergie: Wasserkefir oder isoliertes EPS.', NULL, NULL, NULL, NULL),
  ('xanthan', 'Xanthan (E415)', '⚠️ Säuglinge <12 Monate', 'Infants', 'Relativ', '⚠️ EFSA-Warnung: Nicht in verdickter Säuglingsnahrung (SimPro-Formel)!', 'Darmbeschwerden bei Frühgeborenen.', '⚠️ EFSA: Vorsicht bei Säuglingsnahrung!', NULL, NULL, NULL, NULL),
  ('arabinogalactan', 'Arabinogalactan (Lärche)', '❌❌ Autoimmunerkrankungen', 'Autoimmune Diseases', 'Absolut', '⚠️⚠️ AG stimuliert Immunsystem (NK-Zellen, Makrophagen, TNF-α, IL-6, IFN-γ). Kann Autoimmunreaktionen verstärken!', 'Verschlechterung von MS, SLE, RA, Morbus Crohn, Colitis ulcerosa möglich.', 'WebMD; Drugs.com', NULL, NULL, NULL, NULL),
  ('arabinogalactan', 'Arabinogalactan (Lärche)', '❌❌ Organtransplantation', 'Organ Transplant', 'Absolut', '⚠️⚠️ Immunstimulation kann Abstoßungsreaktion fördern!', 'Erhöhtes Risiko der Organabstoßung.', 'WebMD', NULL, NULL, NULL, NULL),
  ('arabinogalactan', 'Arabinogalactan (Lärche)', '❌ Tuberkulose', 'Tuberculosis', 'Absolut', 'Arabinogalactane sind Bestandteile der Mykobakterien-Zellwand. Theoretische Bedenken.', 'Unklare Wechselwirkung.', 'Drugs.com', NULL, NULL, NULL, NULL),
  ('arabinogalactan', 'Arabinogalactan (Lärche)', '⚠️ Immunsuppressiva-Therapie', 'Immunosuppressive Therapy', 'Relativ', 'AG kann Wirkung von Immunsuppressiva (Ciclosporin, Tacrolimus, etc.) entgegenwirken.', 'Reduzierte Wirksamkeit der Immunsuppression.', 'WebMD', NULL, NULL, NULL, NULL),
  ('arabinogalactan', 'Arabinogalactan (Lärche)', '⚠️ Schwangerschaft/Stillzeit', 'Pregnancy/Lactation', 'Relativ', 'Unzureichende Sicherheitsdaten. Keine klinischen Studien bei Schwangeren.', 'Unbekannte Risiken.', 'Allgemein', NULL, NULL, NULL, NULL),
  ('phgg', 'PHGG (Teilweise hydrolysiertes Guarkernmehl)', '❌ Gastrointestinale Obstruktion', 'GI Obstruction', 'Absolut', 'Bei Ösophagus- oder Darmverschluss/-verengung nicht anwenden.', 'Verschlechterung der Obstruktion möglich.', 'Allgemein', NULL, NULL, NULL, NULL),
  ('phgg', 'PHGG (Teilweise hydrolysiertes Guarkernmehl)', '⚠️ Leguminosen-Allergie', 'Legume Allergy', 'Relativ', 'Guar stammt von Guarbohne (Leguminose). Potenzielle Kreuzreaktivität bei Hülsenfrucht-Allergie.', 'Allergische Reaktion möglich.', 'Allgemein', NULL, NULL, NULL, NULL),
  ('phgg', 'PHGG (Teilweise hydrolysiertes Guarkernmehl)', '⚠️ Säuglinge <12 Wochen', 'Infants <12 weeks', 'Relativ', 'EFSA 2024: Daten nicht ausreichend für sichere Verwendung bei Säuglingen <12 Wochen.', 'Unbekannte Risiken bei sehr jungen Säuglingen.', 'EFSA Journal 2024;22(5):8748', NULL, NULL, NULL, NULL),
  ('lactobacillus-gasseri', 'Lactobacillus gasseri', 'Schwere Immunsuppression', 'Severe Immunosuppression', 'Relativ', 'Theoretisches Translokationsrisiko bei schwerer Immunsuppression. Einzelfälle opportunistischer Infektionen bei prädisponierenden Faktoren.', 'Bakteriämie (selten bei Immungeschwächten)', 'Allgemeine Probiotika-Sicherheitsdaten', NULL, NULL, NULL, NULL),
  ('lactobacillus-gasseri', 'Lactobacillus gasseri', 'Leberzirrhose', 'Liver Cirrhosis', 'Relativ', 'Potentielles Risiko für bakterielle Translokation bei fortgeschrittener Leberzirrhose.', 'Bakterielle Translokation', 'Allgemeine Probiotika-Sicherheitsdaten', NULL, NULL, NULL, NULL),
  ('lactobacillus-gasseri', 'Lactobacillus gasseri', '⚠️ Histaminintoleranz (stammspezifisch!)', 'Histamine Intolerance (strain-specific)', 'Relativ', '⚠️ EINIGE L. gasseri-Stämme können Histamin produzieren! ✅ BNR17: Explizit als frei von biogenen Aminen bestätigt (FDA GRAS).', 'Histamin-Symptome bei empfindlichen Personen', 'FDA GRAS 1089; Literatur', NULL, NULL, NULL, NULL),
  ('lactobacillus-gasseri', 'Lactobacillus gasseri', 'Schwere akute Pankreatitis', 'Severe Acute Pancreatitis', 'Absolut', 'PROPATRIA-Studie gilt für alle Probiotika.', '⚠️ Erhöhte Mortalität!', 'PROPATRIA', NULL, NULL, NULL, NULL),
  ('lactobacillus-helveticus', 'Lactobacillus helveticus', '⚠️⚠️⚠️ MAO-Hemmer-Therapie (KRITISCH!)', 'MAO Inhibitor Therapy (CRITICAL!)', 'Absolut', '⚠️⚠️⚠️ KRITISCHE KONTRAINDIKATION! L. helveticus kann TYRAMIN produzieren (stammabhängig). Bei MAO-Hemmern: Tyramin kann nicht abgebaut werden → HYPERTENSIVE KRISE ("Cheese Reaction").', '⚠️⚠️⚠️ HYPERTENSIVE KRISE! Kopfschmerzen, Blutdruckspitzen >200 mmHg, Herzrhythmusstörungen, potenziell lebensbedrohlich.', 'Pharmakologie MAO-Hemmer', NULL, NULL, NULL, NULL)
