  ('lactobacillus-helveticus', 'Lactobacillus helveticus', '⚠️ Histaminintoleranz (stammspezifisch!)', 'Histamine Intolerance (strain-specific)', 'Relativ', '⚠️ L. helveticus wurde als histaminproduzierender Stamm aus Käsestartern isoliert. Histidin-Decarboxylase-Gene (hdc) in einigen Stämmen nachgewiesen.', 'Histamin-Symptome: Kopfschmerzen, Flush, GI-Beschwerden', 'Burdychova & Komprda 2007; EFSA', NULL, NULL, NULL, NULL),
